+/// Simulated outcome for one candidate pool size.
+#[derive(Debug, Clone, PartialEq, Serialize)]
+pub struct ConnectionPoolSimulationPoint {
+    pub pool_size: usize,
+    pub predicted_active_connections: usize,
+    pub throughput_score: f64,
